import timm
import torch
import torch.nn as nn
from torch.autograd import Function


class GradReverse(Function):
    @staticmethod
    def forward(ctx, x, lambd):
        ctx.lambd = lambd
        return x.view_as(x)

    @staticmethod
    def backward(ctx, grad_output):
        return -ctx.lambd * grad_output, None


def grad_reverse(x, lambd=1.0):
    return GradReverse.apply(x, lambd)


class WildlifeClassifier(nn.Module):
    def __init__(
        self,
        num_classes=10,
        model_name='vit_base_patch16_clip_224.openai',
        dropout=0.3,
        hidden_dim=512,
        freeze_backbone=False,
        num_domains=3,
        use_domain_head=False,
    ):
        super().__init__()
        self.model_name = model_name
        self.use_domain_head = use_domain_head
        # Keep backbone creation offline-safe by only relying on known local timm weights.
        self.backbone = timm.create_model(model_name, pretrained=True, num_classes=0)
        feat_dim = self.backbone.num_features
        self.feat_dim = feat_dim
        self.classifier = nn.Sequential(
            nn.LayerNorm(feat_dim),
            nn.Dropout(dropout),
            nn.Linear(feat_dim, hidden_dim),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, num_classes),
        )
        if use_domain_head:
            self.domain_head = nn.Sequential(
                nn.LayerNorm(feat_dim),
                nn.Linear(feat_dim, hidden_dim // 2),
                nn.GELU(),
                nn.Dropout(dropout),
                nn.Linear(hidden_dim // 2, num_domains),
            )
        else:
            self.domain_head = None
        if freeze_backbone:
            for p in self.backbone.parameters():
                p.requires_grad = False

    def forward_features(self, pixel_values):
        return self.backbone(pixel_values)

    def forward(self, pixel_values):
        feats = self.forward_features(pixel_values)
        return self.classifier(feats)

    def forward_with_domain(self, pixel_values, grl_lambda=1.0):
        feats = self.forward_features(pixel_values)
        class_logits = self.classifier(feats)
        if self.domain_head is None:
            raise RuntimeError('Domain head not enabled for this model.')
        domain_logits = self.domain_head(grad_reverse(feats, grl_lambda))
        return class_logits, domain_logits


def build_model(num_classes=10, **kwargs):
    return WildlifeClassifier(num_classes=num_classes, **kwargs)
